4261   if (Sub)
4262     return nullptr;
4263 
4264   // Match reduce.add(ext(mul(A, B))).
4265   if (match(VecOp, m_ZExtOrSExt(m_Mul(m_VPValue(A), m_VPValue(B))))) {
4266     auto *Ext = cast<VPWidenCastRecipe>(VecOp);
