8327   return new VPReductionRecipe(
8328       Reduction->getOpcode() == Instruction::FAdd ? RecurKind::FAdd
8329                                                   : RecurKind::Add,
8330       Reduction->getOpcode() == Instruction::FAdd
8331           ? Reduction->getFastMathFlags()
8332           : FastMathFlags(),
8333       ReductionI, Accumulator, BinOp, Cond,
