8337 void LoopVectorizationPlanner::buildVPlansWithVPRecipes(ElementCount MinVF,
8338                                                         ElementCount MaxVF) {
8339   if (ElementCount::isKnownGT(MinVF, MaxVF))
8340     return;
8341 
8342   assert(OrigLoop->isInnermost() && "Inner loop expected.");
8343 
8344   const LoopAccessInfo *LAI = Legal->getLAI();
8345   LoopVersioning LVer(*LAI, LAI->getRuntimePointerChecking()->getChecks(),
8346                       OrigLoop, LI, DT, PSE.getSE());
8347   if (!LAI->getRuntimePointerChecking()->getChecks().empty() &&
8348       !LAI->getRuntimePointerChecking()->getDiffChecks()) {
8349     // Only use noalias metadata when using memory checks guaranteeing no
8350     // overlap across all iterations.
8351     LVer.prepareNoAliasMetadata();
8352   }
8353 
8354   // Create initial base VPlan0, to serve as common starting point for all
8355   // candidates built later for specific VF ranges.
8356   auto VPlan0 = VPlanTransforms::buildVPlan0(
8357       OrigLoop, *LI, Legal->getWidestInductionType(),
8358       getDebugLocFromInstOrOperands(Legal->getPrimaryInduction()), PSE, &LVer);
8359 
8360   // Create recipes for header phis.
8361   VPlanTransforms::createHeaderPhiRecipes(
8362       *VPlan0, PSE, *OrigLoop, Legal->getInductionVars(),
8363       Legal->getReductionVars(), Legal->getFixedOrderRecurrences(),
8364       CM.getInLoopReductions(), Hints.allowReordering());
8365 
8366   auto MaxVFTimes2 = MaxVF * 2;
8367   for (ElementCount VF = MinVF; ElementCount::isKnownLT(VF, MaxVFTimes2);) {
8368     VFRange SubRange = {VF, MaxVFTimes2};
8369     if (auto Plan = tryToBuildVPlanWithVPRecipes(
8370             std::unique_ptr<VPlan>(VPlan0->duplicate()), SubRange, &LVer)) {
8371       // Now optimize the initial VPlan.
8372       VPlanTransforms::hoistPredicatedLoads(*Plan, PSE, OrigLoop);
8373       VPlanTransforms::sinkPredicatedStores(*Plan, PSE, OrigLoop);
8374       VPlanTransforms::runPass(VPlanTransforms::truncateToMinimalBitwidths,
8375                                *Plan, CM.getMinimalBitwidths());
8376       VPlanTransforms::runPass(VPlanTransforms::optimize, *Plan);
8377       // TODO: try to put addExplicitVectorLength close to addActiveLaneMask
8378       if (CM.foldTailWithEVL()) {
8379         VPlanTransforms::runPass(VPlanTransforms::addExplicitVectorLength,
8380                                  *Plan, CM.getMaxSafeElements());
8381         VPlanTransforms::runPass(VPlanTransforms::optimizeEVLMasks, *Plan);
8382       }
8383       assert(verifyVPlanIsValid(*Plan) && "VPlan is invalid");
8384       VPlans.push_back(std::move(Plan));
8385     }
8386     VF = SubRange.End;
8387   }
8388 }
